// Stage 2: Native Evaluation Gate in n8n
const job = $json.body || $json;

// Bypass overlap calculation if job is pre-evaluated by the discovery script
if (job.score !== undefined && job.passed !== undefined) {
  return {
    json: {
      job_id: job.job_id || "job_101",
      title: job.title || "Target Job",
      company: job.company || "Target Company",
      apply_url: job.apply_url || job.url || "",
      score: job.score,
      passed: job.passed,
      matched_skills: job.matched_skills || [],
      missing_skills: job.missing_skills || []
    }
  };
}

const coreSkills = [
  "Python", "Java", "JavaScript", "C/C++", "C#/.NET", "SQL",
  "Scikit-learn", "TensorFlow", "PyTorch", "XGBoost", "NumPy", "Pandas",
  "FastAPI", "React", "Node.js", "AWS", "PostgreSQL", "Firebase", "MySQL", "Git"
];

const jobTitle = (job.title || "").toLowerCase();
const jobDesc = (job.description || "").toLowerCase();
const fullJobText = jobTitle + " " + jobDesc;

let matchedSkills = [];
let missingSkills = [];

for (const skill of coreSkills) {
  if (fullJobText.includes(skill.toLowerCase())) {
    matchedSkills.push(skill);
  } else {
    missingSkills.push(skill);
  }
}

const score = Math.round((matchedSkills.length / Math.max(coreSkills.length, 1)) * 100 * 1.5);
const finalScore = Math.min(Math.max(score, 40), 100);
const passed = finalScore >= 70;

return {
  json: {
    job_id: job.job_id || "job_101",
    title: job.title || "Target Job",
    company: job.company || "Target Company",
    apply_url: job.apply_url || job.url || "",
    score: finalScore,
    passed: passed,
    matched_skills: matchedSkills,
    missing_skills: missingSkills
  }
};

